BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT ?elem ?name ?type WHERE {
  ?elem vocab:NamedElement_name "Peak Power Limit Requirement TMT" .
  ?elem rdf:type ?type .
  OPTIONAL { ?elem vocab:NamedElement_name ?name }
}
LIMIT 25

BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT ?vp ?name ?default WHERE {
  ?vp vocab:NamedElement_name ?name .
  FILTER(CONTAINS(STR(?name), "powerPeakLimit")) .
  OPTIONAL { ?vp vocab:Property_defaultValue ?dv .
             ?dv vocab:LiteralString_value ?default }
}
LIMIT 25

